import React, { useState, useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth }  from "../context/AuthContext";
import { useObras } from "../context/ObraContext";
import Header       from "../components/Layout/Header";
import Sidebar      from "../components/Layout/Sidebar";
import Footer       from "../components/Layout/Footer";
import CardResumen  from "../components/Cards/CardResumen";
import Button       from "../components/Shared/Button";
import OrchestradorPanel from "../components/OrchestradorPanel";
import { controlAPI } from "../utils/api";

export default function Dashboard() {
  const navigate          = useNavigate();
  const { user }          = useAuth();
  const { stats, loading, fuente } = useObras();

  const [ahora,          setAhora]     = useState(new Date());
  const [sistemaInfo,    setSistema]   = useState(null);
  const [loadingSistema, setLoadSist]  = useState(true);

  /* Reloj en vivo */
  useEffect(() => {
    const id = setInterval(() => setAhora(new Date()), 1000);
    return () => clearInterval(id);
  }, []);

  /* Estado real del sistema desde el backend */
  useEffect(() => {
    setLoadSist(true);
    controlAPI.getEstado()
      .then((res) => setSistema(res))
      .catch(() => setSistema(null))
      .finally(() => setLoadSist(false));
  }, []);

  const sistemaAbierto = sistemaInfo
    ? sistemaInfo.abierto
    : ahora.getHours() < 12;

  const horaFormateada = ahora.toLocaleTimeString("es-CL", {
    hour: "2-digit", minute: "2-digit", second: "2-digit",
  });

  const tiempoRestante = sistemaInfo?.tiempoRestanteMinutos;
  const formatearRestante = () => {
    if (!tiempoRestante || tiempoRestante <= 0) return null;
    const h = Math.floor(tiempoRestante / 60);
    const m = tiempoRestante % 60;
    return h > 0 ? `${h}h ${m}m` : `${m}m`;
  };

  const handleVerObras = useCallback(() => navigate("/obras"), [navigate]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center" style={{ backgroundColor: "#F5F3F0" }}>
        <div className="text-center">
          <div className="w-8 h-8 border-4 border-t-transparent rounded-full animate-spin mx-auto mb-3"
            style={{ borderColor: "#691C32", borderTopColor: "transparent" }} />
          <p className="text-sm" style={{ color: "#666666" }}>Cargando...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#F5F3F0" }}>
      <Header />

      <div className="flex flex-1">
        <Sidebar />

        <main className="flex-1 px-4 sm:px-6 lg:px-8 py-8 max-w-6xl mx-auto w-full">

          {/* ── Saludo + estado sistema ── */}
          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8 animate-fade-in">
            <div>
              <h1 className="text-2xl font-bold" style={{ color: "#691C32" }}>
                Bienvenido, {user?.nombre || "Administrador"}
              </h1>
              <p className="text-sm mt-1" style={{ color: "#666666" }}>
                {ahora.toLocaleDateString("es-CL", {
                  weekday: "long", day: "numeric", month: "long", year: "numeric",
                })}
              </p>
              {/* Indicador de fuente de datos */}
              {fuente && (
                <span
                  className="inline-flex items-center gap-1 mt-2 text-xs px-2 py-0.5 rounded-full font-medium"
                  style={
                    fuente === "postgresql"
                      ? { backgroundColor: "rgba(0,99,65,0.1)", color: "#006341", border: "1px solid rgba(0,99,65,0.25)" }
                      : { backgroundColor: "rgba(244,184,96,0.2)", color: "#7A5A00", border: "1px solid rgba(244,184,96,0.4)" }
                  }
                >
                  <span
                    className="w-1.5 h-1.5 rounded-full"
                    style={{ backgroundColor: fuente === "postgresql" ? "#006341" : "#C9A66B" }}
                  />
                  {fuente === "postgresql" ? "PostgreSQL" : "datos locales"}
                </span>
              )}
            </div>

            {/* Indicador sistema */}
            <div
              className="flex items-center gap-3 px-4 py-3 rounded-xl"
              style={{
                backgroundColor: sistemaAbierto ? "rgba(0,99,65,0.06)"    : "rgba(232,168,168,0.18)",
                border:          sistemaAbierto ? "1px solid rgba(0,99,65,0.2)" : "1px solid rgba(105,28,50,0.18)",
              }}
            >
              <div className="text-center">
                <div className="flex items-center gap-2 text-sm font-semibold"
                  style={{ color: sistemaAbierto ? "#006341" : "#691C32" }}>
                  <span
                    className={`w-2.5 h-2.5 rounded-full ${sistemaAbierto ? "animate-pulse" : ""}`}
                    style={{ backgroundColor: sistemaAbierto ? "#006341" : "#E8A8A8" }}
                  />
                  {loadingSistema ? "Verificando..." : sistemaAbierto ? "SISTEMA ABIERTO" : "SISTEMA CERRADO"}
                </div>
                <p className="text-xs font-mono mt-0.5" style={{ color: "#666666" }}>{horaFormateada}</p>
                {sistemaAbierto && formatearRestante() && (
                  <p className="text-xs mt-0.5" style={{ color: "#006341" }}>Cierra en {formatearRestante()}</p>
                )}
                {sistemaInfo?.periodo_actual && (
                  <p className="text-xs mt-0.5" style={{ color: "#666666" }}>{sistemaInfo.periodo_actual}</p>
                )}
              </div>
            </div>
          </div>

          {/* ── Cards KPI ── */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5 mb-8">
            <CardResumen
              titulo="Total de obras"
              valor={stats.total}
              subtitulo="Obras registradas"
              icono="🏗️"
              colorClase="text-[#691C32]"
              bgClase="bg-[rgba(105,28,50,0.06)]"
              borderColor="#C9A66B"
            />
            <CardResumen
              titulo="Actualizadas"
              valor={stats.actualizadas}
              subtitulo={`${stats.pct}% del total`}
              icono="✅"
              colorClase="text-[#006341]"
              bgClase="bg-[rgba(0,99,65,0.06)]"
              borderColor="#006341"
            />
            <CardResumen
              titulo="Pendientes"
              valor={stats.pendientes}
              subtitulo={`${stats.total - stats.actualizadas} sin actualizar`}
              icono="⏳"
              colorClase="text-[#691C32]"
              bgClase="bg-[rgba(232,168,168,0.2)]"
              borderColor="#E8A8A8"
            />
          </div>

          {/* ── Barra de progreso global ── */}
          <div
            className="bg-white rounded-2xl p-6 mb-8 animate-fade-in"
            style={{ boxShadow: "0 4px 12px rgba(0,0,0,0.08)", border: "1px solid #D4C4B0" }}
          >
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2 mb-4">
              <div>
                <h2 className="font-semibold" style={{ color: "#2C2C2C" }}>Progreso del corte actual</h2>
                <p className="text-sm mt-0.5" style={{ color: "#666666" }}>
                  {stats.actualizadas} de {stats.total} obras actualizadas
                </p>
              </div>
              <span className="text-3xl font-bold" style={{ color: "#691C32" }}>{stats.pct}%</span>
            </div>

            <div className="w-full rounded-full h-2 overflow-hidden" style={{ backgroundColor: "#F5F3F0" }}>
              <div
                className="h-2 rounded-full transition-all duration-700"
                style={{ width: `${stats.pct}%`, backgroundColor: "#006341" }}
              />
            </div>

            <div className="flex justify-between text-xs mt-2" style={{ color: "#666666" }}>
              <span>0%</span>
              <span className="font-medium" style={{
                color: stats.pct >= 80 ? "#006341" : stats.pct >= 50 ? "#C9A66B" : "#691C32",
              }}>
                {stats.pct >= 80 ? "Buen avance" : stats.pct >= 50 ? "En progreso" : "Requiere atención"}
              </span>
              <span>100%</span>
            </div>
          </div>

          {/* ── Distribución por estado ── */}
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            {[
              { label: "Actualizadas", valor: stats.actualizadas, color: "#006341",
                pct: stats.total ? Math.round(stats.actualizadas / stats.total * 100) : 0 },
              { label: "En progreso",  valor: stats.enProgreso,   color: "#F4B860",
                pct: stats.total ? Math.round(stats.enProgreso   / stats.total * 100) : 0 },
              { label: "Pendientes",   valor: stats.pendientes,   color: "#E8A8A8",
                pct: stats.total ? Math.round(stats.pendientes   / stats.total * 100) : 0 },
            ].map(({ label, valor, color, pct }) => (
              <div
                key={label}
                className="bg-white rounded-xl p-4 transition-all duration-200"
                style={{ border: "1px solid #D4C4B0", boxShadow: "0 2px 8px rgba(0,0,0,0.06)" }}
                onMouseEnter={e => { e.currentTarget.style.boxShadow = "0 4px 12px rgba(0,0,0,0.10)"; }}
                onMouseLeave={e => { e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.06)"; }}
              >
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm" style={{ color: "#666666" }}>{label}</span>
                  <span className="font-bold" style={{ color: "#2C2C2C" }}>{valor}</span>
                </div>
                <div className="w-full rounded-full h-1.5 overflow-hidden" style={{ backgroundColor: "#F5F3F0" }}>
                  <div className="h-1.5 rounded-full transition-all duration-500"
                    style={{ width: `${pct}%`, backgroundColor: color }} />
                </div>
                <p className="text-xs mt-1" style={{ color: "#666666" }}>{pct}%</p>
              </div>
            ))}
          </div>

          {/* ── Asistente de consultas ── */}
          <div className="mb-8 animate-fade-in">
            <OrchestradorPanel />
          </div>

          {/* ── CTA ── */}
          <div
            className="rounded-2xl p-6 flex flex-col sm:flex-row items-center justify-between gap-4 animate-fade-in"
            style={{ background: "linear-gradient(135deg, #691C32 0%, #550A1F 100%)" }}
          >
            <div>
              <h3 className="font-bold text-lg text-white">Ver todas las obras</h3>
              <p className="text-sm mt-1" style={{ color: "rgba(255,255,255,0.75)" }}>
                Accede al listado completo y actualiza el avance de cada obra.
              </p>
            </div>
            <Button
              variant="secondary"
              size="lg"
              onClick={handleVerObras}
              className="shrink-0"
              aria-label="Ir al listado completo de obras"
            >
              Ver obras →
            </Button>
          </div>

        </main>
      </div>

      <Footer />
    </div>
  );
}
